  1	import * as React from 'react';
  2	import {
  3	  TextInputTypes,
  4	  Button,
  5	  FormGroup,
  6	  Tooltip,
  7	  Flex,
  8	  FlexItem,
  9	} from '@patternfly/react-core';
 10	import { MinusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/minus-circle-icon';
 11	import { PlusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/plus-circle-icon';
 12	import { FieldArray, useFormikContext, FormikValues } from 'formik';
 13	import * as _ from 'lodash';
 14	import { useTranslation } from 'react-i18next';
 15	import { useFormikValidationFix } from '../../pipelines-details/multi-column-field/formik-validation-fix';
 16	import InputField from '../../pipelines-details/multi-column-field/InputField';
 17	import { getFieldId } from '../../pipelines-details/multi-column-field/utils';
 18	import DropdownField from '../../common/DropdownField';
 19	import './MultipleKeySelector.scss';
 20	
 21	interface MultipleKeySelectorProps {
 22	  name: string;
 23	  keys: { [key: string]: string };
 24	  addString?: string;
 25	  tooltip?: string;
 26	}
 27	
 28	const MultipleKeySelector: React.FC<MultipleKeySelectorProps> = ({
 29	  name,
 30	  keys,
 31	  addString,
 32	  tooltip,
 33	}) => {
 34	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 35	  const { values } = useFormikContext<FormikValues>();
 36	  const items = _.get(values, name, []);
 37	  useFormikValidationFix(items);
 38	  return (
 39	    <FieldArray
 40	      name={name}
 41	      key="multiple-key-selector"
 42	      render={({ push, remove }) => {
 43	        return (
 44	          <FormGroup
 45	            fieldId={getFieldId(name, 'multiple-key-selector')}
 46	            label={t('Items')}
 47	            className="odc-multiple-key-selector"
 48	          >
 49	            {items.length > 0 &&
 50	              items.map((item, index) => {
 51	                const fieldKey = `${name}.${index}.${item.key}`;
 52	                return (
 53	                  <div
 54	                    className="form-group odc-multiple-key-selector__item"
 55	                    key={fieldKey}
 56	                  >
 57	                    <Flex direction={{ default: 'column', lg: 'row' }}>
 58	                      <FlexItem grow={{ default: 'grow' }}>
 59	                        <DropdownField
 60	                          name={`${name}.${index}.key`}
 61	                          title={t('Select a key')}
 62	                          items={keys}
 63	                          fullWidth
 64	                        />
 65	                      </FlexItem>
 66	                      <FlexItem grow={{ default: 'grow' }}>
 67	                        <InputField
 68	                          name={`${name}.${index}.path`}
 69	                          type={TextInputTypes.text}
 70	                          placeholder={t('Enter a path')}
 71	                        />
 72	                      </FlexItem>
 73	                    </Flex>
 74	                    <div className="odc-multiple-key-selector__deleteButton">
 75	                      <Tooltip content={tooltip || t('Remove')}>
 76	                        <MinusCircleIcon
 77	                          aria-hidden="true"
 78	                          onClick={() => remove(index)}
 79	                        />
 80	                      </Tooltip>
 81	                    </div>
 82	                  </div>
 83	                );
 84	              })}
 85	            <Button
 86	              variant="link"
 87	              onClick={() => push({ key: '', path: '' })}
 88	              icon={<PlusCircleIcon />}
 89	              isInline
 90	            >
 91	              {addString || t('Add items')}
 92	            </Button>
 93	          </FormGroup>
 94	        );
 95	      }}
 96	    />
 97	  );
 98	};
 99	
100	export default MultipleKeySelector;

